import{_ as e,o as i,c as a,a as n}from"./app.09e3ab02.js";const g=JSON.parse('{"title":"Seekinq v. iOminous, Jan 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/seekinq_v_iominous_jan2018.md","lastUpdated":1666055355000}'),t={name:"government/court-cases-precedents/seekinq_v_iominous_jan2018.md"},s=n('<h1 id="seekinq-v-iominous-jan-2018" tabindex="-1">Seekinq v. iOminous, Jan 2018 <a class="header-anchor" href="#seekinq-v-iominous-jan-2018" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: TheOrangeWizard</p><p><strong>Date</strong>: 14th January 2018</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><p>The charge is misrepresentation/unfairness in transaction. Seekinq bought 3 stacks of uncooked fish from iOminous in exchange for a \u201Cbuild job\u201D which has turned out to be much larger than anticipated.</p><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>iOminous pleads not guilty.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>iOminous claims the terms were fully agreed on.</p></li><li><p>Seekinq reiterates that he was expecting a build job rather than having to build a whole town.</p></li><li><p>iOminous clarifies he did change the build he wanted Seekinq to do but asserts Seekinq owes him the work nonetheless.</p></li><li><p>Seekinq says the fish were worth 3-5 diamonds and that the magnitude of the build job is 64-128 diamonds.</p></li><li><p>iOminous claims he supplied the fish under urgency and that the demand and thus value of them was high. iOminous provides a picture of a large building with an onion dome on a mushrrom island that he expects Seekinq to now build (with some assistance), Seekinq refuses.</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>The blame falls partially on both parties, iOminous for not providing adequate terms and on Seekinq for not confirming the terms before accepting the deal. However, as &quot;a build&quot; generally refers to a single building, I believe it was reasonable for Seekinq to assume it would be a single building. Therefore the court requires Seekinq to complete a single, reasonably-sized building in payment.</p>',11),o=[s];function r(h,l,d,c,u,p){return i(),a("div",null,o)}const _=e(t,[["render",r]]);export{g as __pageData,_ as default};
